interface WalletModalProps {
  isOpen: boolean;
  onClose: () => void;
  onWalletSelect?: (walletName: string) => void;
}

export default function WalletModal({ isOpen, onClose, onWalletSelect }: WalletModalProps) {
  const [selectedWallet, setSelectedWallet] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleWalletClick = (walletName: string) => {
    setSelectedWallet(walletName);
    if (onWalletSelect) {
      onWalletSelect(walletName);
    }
  };

  // Find the selected wallet object cleanly so we can pull its image
  const selected = wallets.find((w) => w.name === selectedWallet);

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-[2px] animate-in fade-in duration-300">
      
      <div className="absolute inset-0" onClick={onClose}></div>

      <div className="relative bg-white rounded-[32px] flex w-full max-w-[700px] h-[480px] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 zoom-in-95 duration-300 ease-out">
        
        <button 
          onClick={onClose} 
          className="absolute top-4 right-4 w-8 h-8 flex items-center justify-center rounded-full hover:bg-black/5 text-slate-400 transition-colors z-10"
        >
          <i className="fas fa-times text-[14px]"></i>
        </button>

        {/* LEFT SIDE - Wallet List */}
        <div className="w-[340px] flex flex-col pt-6 pb-2 px-2 border-r border-slate-100 shrink-0 bg-white">
          
          <div className="flex items-center gap-2 px-4 mb-6">
            <div className="bg-[#141414] text-white text-[11px] font-bold px-3 py-1 rounded-full tracking-wide">
              reown
            </div>
            <span className="text-[13px] font-medium text-slate-700 tracking-tight">Manual Kit</span>
          </div>

          <div className="px-4 mb-2">
            <span className="text-[13px] font-semibold text-slate-500">Popular:</span>
          </div>

          <div className="flex-1 overflow-y-auto px-2 custom-scrollbar">
            {wallets.map((wallet) => (
              <button 
                key={wallet.id}
                onClick={() => handleWalletClick(wallet.name)}
                className={`w-full flex items-center justify-between p-2.5 rounded-[16px] transition-colors ${selectedWallet === wallet.name ? 'bg-slate-100' : 'hover:bg-slate-50'}`}
              >
                <div className="flex items-center gap-3">
                  <img 
                    src={wallet.icon} 
                    alt={wallet.name} 
                    className="w-[36px] h-[36px] rounded-[10px] object-contain"
                  />
                  <span className="text-[14px] font-bold text-slate-900 tracking-tight">{wallet.name}</span>
                </div>
                
                {wallet.recommended && (
                  <div className="bg-[#E0F2FE] text-[#0284C7] text-[9px] font-bold px-2 py-[2px] rounded uppercase tracking-wider mt-0.5">
                    Recommended
                  </div>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* RIGHT SIDE - Status Area with Smooth Crossfade */}
        <div className="flex-1 bg-[#F4F4F5] relative overflow-hidden">
          
          {/* Default State (Globe) - Fades out and slides down when clicked */}
          <div className={`absolute inset-0 flex flex-col items-center justify-center p-8 text-center transition-all duration-700 ease-in-out ${!selectedWallet ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
            <div className="w-[56px] h-[56px] rounded-full flex items-center justify-center text-slate-400 mb-4">
              <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="1">
                <path strokeLinecap="round" strokeLinejoin="round" d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" />
              </svg>
            </div>
            <p className="text-[14px] font-medium text-slate-600 max-w-[160px] leading-snug">
              Connect your wallet to get started
            </p>
          </div>

          {/* Loading State (Dashed Spinner + Logo) - Fades in and slides up seamlessly */}
          <div className={`absolute inset-0 flex flex-col items-center justify-center p-8 text-center transition-all duration-700 ease-in-out ${selectedWallet ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}`}>
            
            <div className="relative w-[72px] h-[72px] flex items-center justify-center mb-6">
              {/* Outer Dashed Ring (slow spin) */}
              <div className="absolute inset-0 border-[2px] border-dashed border-slate-300 rounded-full animate-[spin_4s_linear_infinite]"></div>
              
              {/* Inner Accent Ring (faster spin) */}
              <div className="absolute inset-1.5 border-[2px] border-[#3B82F6] border-t-transparent border-l-transparent rounded-full animate-[spin_1.5s_cubic-bezier(0.5,0,0.5,1)_infinite]"></div>
              
              {/* Selected Wallet Logo sitting perfectly in the center */}
              {selected?.icon && (
                <img 
                  src={selected.icon} 
                  alt={selected.name} 
                  className="w-[36px] h-[36px] rounded-lg object-contain relative z-10 animate-pulse"
                />
              )}
            </div>

            <p className="text-[16px] font-bold text-slate-900 tracking-tight">
              Continue in {selectedWallet}
            </p>
            <p className="text-[13px] text-slate-500 mt-1">
              Accept connection request in your wallet
            </p>

          </div>

        </div>

      </div>
    </div>
  );
}